22	const maxTagsPerResource = 20
23	const maxTagLength = 32
24	
25	var (
26		ErrResourceNotFound     = errors.New("resource not found")
27		ErrTooManyTags          = errors.New("maximum 20 tags per resource")
28		ErrTagTooLong           = errors.New("tag must be at most 32 characters")
29		ErrMimeTypeNotAllowed   = errors.New("mime type is not in the allowlist")
30		ErrVersionNotFound          = errors.New("version not found")
31		ErrResourceAccessDenied     = errors.New("access denied to this resource")
32		ErrExtractedTextNotAllowed  = errors.New("extracted_text is only allowed for PDF and DOCX files")
33	)
