65	func (s *ResourceService) CreateResource(ctx context.Context, req *dto.CreateResourceRequest, actorID uuid.UUID, callerRole models.Role) (*models.Resource, []string, error) {
66		courseID, err := uuid.Parse(req.CourseID)
67		if err != nil {
68			return nil, nil, fmt.Errorf("invalid course_id")
69		}
70		if _, err := s.courseRepo.GetByID(ctx, courseID); err != nil {
71			return nil, nil, fmt.Errorf("course not found")
72		}
73	
74		// Require course staff or admin to create resources
75		if err := s.requireCourseStaff(ctx, courseID, actorID, callerRole); err != nil {
76			return nil, nil, err
77		}
78	
79		if req.Title == "" {
80			return nil, nil, fmt.Errorf("title is required")
81		}
82	
83		resType := models.ResourceType(req.ResourceType)
84		if !models.ValidResourceTypes[resType] {
85			return nil, nil, fmt.Errorf("invalid resource_type: %s", req.ResourceType)
86		}
87	
88		visibility := models.ResourceVisibility(req.Visibility)
89		if !models.ValidVisibilities[visibility] {
90			return nil, nil, fmt.Errorf("invalid visibility: %s", req.Visibility)
91		}
92	
93		if resType == models.ResourceTypeLink && (req.LinkURL == nil || *req.LinkURL == "") {
94			return nil, nil, fmt.Errorf("link_url is required for Link resources")
95		}
96	
97		// Validate tags
98		if err := validateTags(req.Tags); err != nil {
99			return nil, nil, err
100		}
101	
102		var nodeID *uuid.UUID
103		if req.NodeID != nil {
104			nid, err := uuid.Parse(*req.NodeID)
105			if err != nil {
106				return nil, nil, fmt.Errorf("invalid node_id")
107			}
108			nodeID = &nid
109		}
110	
111		now := time.Now()
112		resource := &models.Resource{
113			ID:           uuid.New(),
114			CourseID:     courseID,
115			NodeID:       nodeID,
116			Title:        req.Title,
117			Description:  req.Description,
118			ResourceType: resType,
119			Visibility:   visibility,
120			LinkURL:      req.LinkURL,
121			CreatedBy:    actorID,
122			CreatedAt:    now,
123			UpdatedAt:    now,
124		}
125	
126		if err := s.resourceRepo.Create(ctx, resource); err != nil {
127			return nil, nil, err
128		}
129	
130		// Create tags
131		tags := s.saveTags(ctx, resource.ID, req.Tags)
132	
133		s.audit.Log(ctx, "resource", resource.ID, actorID, "created", map[string]interface{}{
134			"course_id":     courseID,
135			"title":         req.Title,
136			"resource_type": string(resType),
137			"visibility":    string(visibility),
138		})
139	
140		return resource, tags, nil
141	}
