143	func (s *ResourceService) GetResource(ctx context.Context, id, callerID uuid.UUID, callerRole models.Role) (*models.Resource, []string, error) {
144		resource, err := s.resourceRepo.GetByID(ctx, id)
145		if err != nil {
146			return nil, nil, ErrResourceNotFound
147		}
148	
149		if err := s.checkResourceAccess(ctx, resource, callerID, callerRole); err != nil {
150			return nil, nil, err
151		}
152	
153		tags, _ := s.getTagStrings(ctx, id)
154		return resource, tags, nil
155	}
