157	func (s *ResourceService) ListResources(ctx context.Context, courseID, callerID uuid.UUID, callerRole models.Role, offset, limit int) ([]models.Resource, error) {
158		if limit <= 0 {
159			limit = 20
160		}
161		if limit > 100 {
162			limit = 100
163		}
164	
165		// Determine visibility based on membership
166		if callerRole == models.RoleAdministrator {
167			return s.resourceRepo.ListByCourse(ctx, courseID, offset, limit)
168		}
169	
170		m, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, courseID)
171		if err != nil {
172			return nil, ErrNotCourseMember
173		}
174	
175		if m.Role == models.MembershipRoleStaff {
176			return s.resourceRepo.ListByCourse(ctx, courseID, offset, limit)
177		}
178	
179		// Enrolled users see only Enrolled-visibility resources
180		return s.resourceRepo.ListByCourseAndVisibility(ctx, courseID, models.VisibilityEnrolled, offset, limit)
181	}
