274	// Version management
275	
276	func (s *ResourceService) UploadVersion(ctx context.Context, resourceID uuid.UUID, fileName, mimeType string, sizeBytes int64, fileContent io.Reader, extractedText *string, actorID uuid.UUID, callerRole models.Role) (*models.ResourceVersion, error) {
277		resource, err := s.resourceRepo.GetByID(ctx, resourceID)
278		if err != nil {
279			return nil, ErrResourceNotFound
280		}
281	
282		// Require course staff or admin
283		if err := s.requireCourseStaff(ctx, resource.CourseID, actorID, callerRole); err != nil {
284			return nil, err
285		}
286	
287		// Validate mime type
288		if !models.AllowedMimeTypes[mimeType] {
289			return nil, fmt.Errorf("%w: %s", ErrMimeTypeNotAllowed, mimeType)
290		}
291	
292		// Reject extracted_text for non-PDF/DOCX files
293		if extractedText != nil && *extractedText != "" && !models.TextExtractableMimeTypes[mimeType] {
294			return nil, ErrExtractedTextNotAllowed
295		}
296	
297		// Compute SHA-256 while writing to disk
298		storageDir := filepath.Join(s.cfg.StoragePath, resource.CourseID.String(), resourceID.String())
299		if err := os.MkdirAll(storageDir, 0750); err != nil {
300			return nil, fmt.Errorf("creating storage directory: %w", err)
301		}
302	
303		versionID := uuid.New()
304		storagePath := filepath.Join(storageDir, versionID.String())
305	
306		f, err := os.Create(storagePath)
307		if err != nil {
308			return nil, fmt.Errorf("creating file: %w", err)
309		}
310	
311		hasher := sha256.New()
312		written, err := io.Copy(f, io.TeeReader(fileContent, hasher))
313		f.Close()
314		if err != nil {
315			os.Remove(storagePath)
316			return nil, fmt.Errorf("writing file: %w", err)
317		}
318	
319		sha256Hash := hex.EncodeToString(hasher.Sum(nil))
320	
321		// Check for deduplication — if same hash exists, reuse storage path
322		existing, err := s.versionRepo.GetBySHA256(ctx, sha256Hash)
323		if err == nil && existing != nil {
324			// Same file already exists — remove the new copy and reference existing path
325			os.Remove(storagePath)
326			storagePath = existing.StoragePath
327		}
328	
329		// Get next version number
330		latestNum, err := s.versionRepo.GetLatestVersionNumber(ctx, resourceID)
331		if err != nil {
332			return nil, fmt.Errorf("getting latest version: %w", err)
333		}
334	
335		version := &models.ResourceVersion{
336			ID:            versionID,
337			ResourceID:    resourceID,
338			VersionNumber: latestNum + 1,
339			FileName:      fileName,
340			MimeType:      mimeType,
341			SizeBytes:     written,
342			SHA256Hash:    sha256Hash,
343			StoragePath:   storagePath,
344			ExtractedText: extractedText,
345			UploadedBy:    actorID,
346			CreatedAt:     time.Now(),
347		}
348	
349		if err := s.versionRepo.Create(ctx, version); err != nil {
350			return nil, err
351		}
352	
353		// Update latest version pointer
354		if err := s.resourceRepo.UpdateLatestVersion(ctx, resourceID, versionID); err != nil {
355			return nil, err
356		}
357	
358		s.audit.Log(ctx, "resource_version", versionID, actorID, "uploaded", map[string]interface{}{
359			"resource_id":    resourceID,
360			"version_number": version.VersionNumber,
361			"file_name":      fileName,
362			"mime_type":      mimeType,
363			"size_bytes":     written,
364			"sha256_hash":    sha256Hash,
365		})
366	
367		return version, nil
368	}
