389	func (s *ResourceService) GetDownloadPath(ctx context.Context, versionID, callerID uuid.UUID, callerRole models.Role) (*models.ResourceVersion, error) {
390		version, err := s.versionRepo.GetByID(ctx, versionID)
391		if err != nil {
392			return nil, ErrVersionNotFound
393		}
394	
395		resource, err := s.resourceRepo.GetByID(ctx, version.ResourceID)
396		if err != nil {
397			return nil, ErrResourceNotFound
398		}
399	
400		if err := s.checkResourceAccess(ctx, resource, callerID, callerRole); err != nil {
401			return nil, err
402		}
403	
404		return version, nil
405	}
