407	// Access control
408	
409	func (s *ResourceService) checkResourceAccess(ctx context.Context, resource *models.Resource, callerID uuid.UUID, callerRole models.Role) error {
410		if callerRole == models.RoleAdministrator {
411			return nil
412		}
413	
414		m, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, resource.CourseID)
415		if err != nil {
416			if errors.Is(err, sql.ErrNoRows) {
417				return ErrResourceAccessDenied
418			}
419			return err
420		}
421	
422		// Staff can see everything
423		if m.Role == models.MembershipRoleStaff {
424			return nil
425		}
426	
427		// Enrolled users can only see Enrolled-visibility resources
428		if resource.Visibility == models.VisibilityStaff {
429			return ErrResourceAccessDenied
430		}
431	
432		return nil
433	}
434	
435	// Course-level authorization helpers
436	
437	func (s *ResourceService) requireCourseStaff(ctx context.Context, courseID, actorID uuid.UUID, callerRole models.Role) error {
438		if callerRole == models.RoleAdministrator {
439			return nil
440		}
441		m, err := s.memberRepo.GetByAccountAndCourse(ctx, actorID, courseID)
442		if err != nil {
443			return ErrResourceAccessDenied
444		}
445		if m.Role != models.MembershipRoleStaff {
446			return ErrResourceAccessDenied
447		}
448		return nil
449	}
450	
451	func (s *ResourceService) checkCourseMembership(ctx context.Context, courseID, callerID uuid.UUID, callerRole models.Role) error {
452		if callerRole == models.RoleAdministrator {
453			return nil
454		}
455		_, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, courseID)
456		if err != nil {
457			return ErrNotCourseMember
458		}
459		return nil
460	}
461	
462	// Tag helpers
463	
464	func validateTags(tags []string) error {
465		if len(tags) > maxTagsPerResource {
466			return ErrTooManyTags
467		}
468		for _, t := range tags {
469			if len(t) > maxTagLength {
470				return fmt.Errorf("%w: '%s'", ErrTagTooLong, t)
471			}
472			if t == "" {
473				return fmt.Errorf("tags cannot be empty strings")
474			}
475		}
476		return nil
477	}
478	
479	func (s *ResourceService) saveTags(ctx context.Context, resourceID uuid.UUID, tagStrings []string) []string {
480		now := time.Now()
481		for _, t := range tagStrings {
482			tag := &models.ResourceTag{
483				ID:         uuid.New(),
484				ResourceID: resourceID,
485				Tag:        t,
486				CreatedAt:  now,
487			}
488			s.tagRepo.Create(ctx, tag)
489		}
490		return tagStrings
491	}
492	
493	func (s *ResourceService) replaceTags(ctx context.Context, resourceID uuid.UUID, tagStrings []string) []string {
494		now := time.Now()
495		tags := make([]models.ResourceTag, len(tagStrings))
496		for i, t := range tagStrings {
497			tags[i] = models.ResourceTag{
498				ID:         uuid.New(),
499				ResourceID: resourceID,
500				Tag:        t,
501				CreatedAt:  now,
502			}
503		}
504		s.tagRepo.ReplaceAll(ctx, resourceID, tags)
505		return tagStrings
506	}
507	
508	func (s *ResourceService) getTagStrings(ctx context.Context, resourceID uuid.UUID) ([]string, error) {
509		tags, err := s.tagRepo.ListByResource(ctx, resourceID)
510		if err != nil {
511			return nil, err
512		}
513		result := make([]string, len(tags))
514		for i, t := range tags {
515			result[i] = t.Tag
516		}
517		return result, nil
518	}
