56			FROM resources WHERE course_id = $1 AND visibility = $2 ORDER BY created_at DESC LIMIT $3 OFFSET $4`
57		if err := r.db.SelectContext(ctx, &resources, query, courseID, visibility, limit, offset); err != nil {
58			return nil, fmt.Errorf("resource_repo.ListByCourseAndVisibility: %w", err)
