63	func (r *ResourceRepository) ListByNode(ctx context.Context, nodeID uuid.UUID) ([]models.Resource, error) {
64		var resources []models.Resource
65		query := `SELECT id, course_id, node_id, title, description, resource_type, visibility, link_url, latest_version_id, created_by, created_at, updated_at
66			FROM resources WHERE node_id = $1 ORDER BY title`
67		if err := r.db.SelectContext(ctx, &resources, query, nodeID); err != nil {
