216	// RetrySettlement retries a failed settlement (up to MaxSettlementRetries).
217	// On retry, it moves back to Obligation for the clerk to re-sign.
218	func (s *PaymentService) RetrySettlement(ctx context.Context, paymentID, actorID uuid.UUID) (*models.PaymentLedgerEntry, error) {
219		entry, err := s.repo.GetByID(ctx, paymentID)
220		if err != nil {
221			return nil, ErrPaymentNotFound
222		}
223	
224		if entry.Status != models.PaymentFailed {
225			return nil, ErrNotFailed
226		}
227	
228		if entry.RetryCount >= models.MaxSettlementRetries {
229			return nil, ErrMaxRetriesExceeded
230		}
231	
232		entry.RetryCount++
233		entry.Status = models.PaymentObligation
234		entry.FinanceClerkID = nil
235		entry.SettledAt = nil
236	
237		if err := s.repo.Update(ctx, entry); err != nil {
238			return nil, err
239		}
240	
241		s.audit.Log(ctx, "payment", paymentID, actorID, "settlement_retried", map[string]interface{}{
242			"account_id":  entry.AccountID,
243			"retry_count": entry.RetryCount,
244			"amount_usd":  entry.AmountUSD.String(),
245		})
246	
247		return entry, nil
248	}
