380	func (s *PaymentService) writeCSV(path string, entries []models.PaymentLedgerEntry) error {
381		f, err := os.Create(path)
382		if err != nil {
383			return err
384		}
385		defer f.Close()
386	
387		w := csv.NewWriter(f)
388		defer w.Flush()
389	
390		// Header
391		w.Write([]string{
392			"id", "account_id", "idempotency_key", "amount_usd", "description",
393			"channel", "status", "finance_clerk_id", "retry_count",
394			"reference_type", "reference_id", "created_at", "settled_at",
395		})
396	
397		for _, e := range entries {
398			desc := ""
399			if e.Description != nil {
400				desc = *e.Description
401			}
402			clerkID := ""
403			if e.FinanceClerkID != nil {
404				clerkID = e.FinanceClerkID.String()
405			}
406			refType := ""
407			if e.ReferenceType != nil {
408				refType = *e.ReferenceType
409			}
410			refID := ""
411			if e.ReferenceID != nil {
412				refID = e.ReferenceID.String()
413			}
414			settledAt := ""
415			if e.SettledAt != nil {
416				settledAt = e.SettledAt.Format(time.RFC3339)
417			}
418	
419			w.Write([]string{
420				e.ID.String(),
421				e.AccountID.String(),
422				e.IdempotencyKey,
423				e.AmountUSD.String(),
424				desc,
425				string(e.Channel),
426				string(e.Status),
427				clerkID,
428				fmt.Sprintf("%d", e.RetryCount),
429				refType,
430				refID,
431				e.CreatedAt.Format(time.RFC3339),
432				settledAt,
433			})
434		}
435	
436		return nil
437	}
