114			COALESCE(SUM(CASE WHEN status = 'Obligation' THEN amount_usd ELSE 0 END), 0) AS total_obligations,
115			COALESCE(SUM(CASE WHEN status = 'Settled' THEN amount_usd ELSE 0 END), 0) AS total_settled,
116			COALESCE(SUM(CASE WHEN status = 'Failed' THEN amount_usd ELSE 0 END), 0) AS total_failed,
117			COUNT(*) AS entry_count
118			FROM payments_ledger
119			WHERE created_at >= $1::date AND created_at < ($1::date + INTERVAL '1 day')`
120		if err := r.db.QueryRowxContext(ctx, query, date).StructScan(&summary); err != nil {
