56		now := time.Now()
57		account := &models.Account{
58			ID:           uuid.New(),
59			Username:     req.Username,
60			PasswordHash: string(hash),
61			Role:         role,
62			Status:       models.StatusActive,
63			CreatedAt:    now,
64			UpdatedAt:    now,
65		}
66	
67		if err := s.accountRepo.Create(ctx, account); err != nil {
68			if strings.Contains(err.Error(), "duplicate") || strings.Contains(err.Error(), "unique") {
69				return nil, fmt.Errorf("%w: %s", ErrDuplicateUsername, req.Username)
70			}
71			return nil, err
72		}
73		return account, nil
74	}
