17		"golang.org/x/crypto/bcrypt"
18	)
19	
20	var (
21		ErrInvalidCredentials = errors.New("invalid username or password")
22		ErrAccountLocked      = errors.New("account is temporarily locked due to too many failed login attempts")
23		ErrAccountNotActive   = errors.New("account is not active")
24		ErrTokenInvalid       = errors.New("invalid or expired refresh token")
25		ErrTokenReuse         = errors.New("refresh token reuse detected, all sessions revoked")
26		ErrPasswordPolicy     = errors.New("password does not meet policy requirements")
27	)
28	
29	type AuthService struct {
30		accountRepo      *repository.AccountRepository
31		refreshTokenRepo *repository.RefreshTokenRepository
32		loginAttemptRepo *repository.LoginAttemptRepository
33		tokenService     *TokenService
