39	func NewAuthService(
40		accountRepo *repository.AccountRepository,
41		refreshTokenRepo *repository.RefreshTokenRepository,
42		loginAttemptRepo *repository.LoginAttemptRepository,
43		tokenService *TokenService,
44		deviceService *DeviceService,
45		cfg *config.Config,
46	) *AuthService {
47		return &AuthService{
48			accountRepo:      accountRepo,
49			refreshTokenRepo: refreshTokenRepo,
50			loginAttemptRepo: loginAttemptRepo,
51			tokenService:     tokenService,
52			deviceService:    deviceService,
53			cfg:              cfg,
54		}
