20	func (h *AuthHandler) Login(c echo.Context) error {
21		var req dto.LoginRequest
22		if err := c.Bind(&req); err != nil {
23			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
24		}
25		if req.Username == "" || req.Password == "" {
26			return echo.NewHTTPError(http.StatusBadRequest, "username and password are required")
27		}
28	
29		resp, err := h.authService.Login(c.Request().Context(), &req, c.RealIP())
30		if err != nil {
31			switch {
32			case errors.Is(err, service.ErrInvalidCredentials):
33				return echo.NewHTTPError(http.StatusUnauthorized, err.Error())
34			case errors.Is(err, service.ErrAccountLocked):
35				return echo.NewHTTPError(http.StatusLocked, err.Error())
36			case errors.Is(err, service.ErrAccountNotActive):
37				return echo.NewHTTPError(http.StatusForbidden, err.Error())
38			default:
39				return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
40			}
41		}
42	
43		return c.JSON(http.StatusOK, resp)
44	}
45	
46	func (h *AuthHandler) Refresh(c echo.Context) error {
47		var req dto.RefreshRequest
48		if err := c.Bind(&req); err != nil {
49			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
50		}
51		if req.RefreshToken == "" {
52			return echo.NewHTTPError(http.StatusBadRequest, "refresh_token is required")
53		}
54	
55		resp, err := h.authService.Refresh(c.Request().Context(), req.RefreshToken)
56		if err != nil {
57			switch {
58			case errors.Is(err, service.ErrTokenInvalid):
59				return echo.NewHTTPError(http.StatusUnauthorized, err.Error())
60			case errors.Is(err, service.ErrTokenReuse):
61				return echo.NewHTTPError(http.StatusUnauthorized, err.Error())
62			case errors.Is(err, service.ErrAccountNotActive):
63				return echo.NewHTTPError(http.StatusForbidden, err.Error())
64			default:
65				return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
66			}
67		}
68	
69		return c.JSON(http.StatusOK, resp)
70	}
71	
72	func (h *AuthHandler) Logout(c echo.Context) error {
73		var req dto.LogoutRequest
74		if err := c.Bind(&req); err != nil {
75			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
76		}
77		if req.RefreshToken == "" {
78			return echo.NewHTTPError(http.StatusBadRequest, "refresh_token is required")
79		}
80	
81		if err := h.authService.Logout(c.Request().Context(), req.RefreshToken); err != nil {
82			return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
83		}
84	
85		return c.NoContent(http.StatusNoContent)
86	}
