35	func (s *AuditService) Log(ctx context.Context, entityType string, entityID, actorID uuid.UUID, action string, details interface{}) {
36		s.LogExtended(ctx, &AuditEntry{
37			EntityType: entityType,
38			EntityID:   entityID,
39			ActorID:    actorID,
40			Action:     action,
41			Details:    details,
42			Tier:       models.TierOperation,
