46	// AuditEntry is the extended input for LogExtended
47	type AuditEntry struct {
48		EntityType     string
49		EntityID       uuid.UUID
50		ActorID        uuid.UUID
51		Action         string
52		Details        interface{}
53		Tier           models.LogTier
54		Reason         *string
55		Source         *string
56		Workstation    *string
57		BeforeSnapshot interface{}
