61	// LogExtended records an audit entry with all extended fields
62	func (s *AuditService) LogExtended(ctx context.Context, entry *AuditEntry) {
63		var detailsJSON json.RawMessage
64		if entry.Details != nil {
65			if b, err := json.Marshal(entry.Details); err == nil {
66				detailsJSON = b
67			}
68		}
69		var beforeJSON json.RawMessage
70		if entry.BeforeSnapshot != nil {
71			if b, err := json.Marshal(entry.BeforeSnapshot); err == nil {
72				beforeJSON = b
73			}
74		}
75		var afterJSON json.RawMessage
76		if entry.AfterSnapshot != nil {
77			if b, err := json.Marshal(entry.AfterSnapshot); err == nil {
78				afterJSON = b
79			}
80		}
81	
82		tier := entry.Tier
83		if tier == "" {
84			tier = models.TierOperation
85		}
86	
87		now := time.Now()
88	
89		// Compute content hash for integrity
90		hashInput := fmt.Sprintf("%s|%s|%s|%s|%s|%s",
91			entry.EntityType, entry.EntityID, entry.ActorID,
92			entry.Action, string(detailsJSON), now.Format(time.RFC3339Nano))
93		h := sha256.Sum256([]byte(hashInput))
94		contentHash := hex.EncodeToString(h[:])
95	
96		// Compute expiration based on tier
97		var expiresAt *time.Time
98		if days, ok := models.TierRetentionDays[tier]; ok {
99			exp := now.Add(time.Duration(days) * 24 * time.Hour)
100			expiresAt = &exp
101		}
102	
103		log := &models.AuditLog{
104			ID:             uuid.New(),
105			EntityType:     entry.EntityType,
106			EntityID:       entry.EntityID,
107			Action:         entry.Action,
108			ActorID:        entry.ActorID,
109			Details:        detailsJSON,
110			Tier:           tier,
111			Reason:         entry.Reason,
112			Source:         entry.Source,
113			Workstation:    entry.Workstation,
114			BeforeSnapshot: beforeJSON,
115			AfterSnapshot:  afterJSON,
116			ContentHash:    &contentHash,
117			ExpiresAt:      expiresAt,
118			CreatedAt:      now,
119		}
120		// Best-effort logging — don't fail the main operation
121		s.repo.Create(ctx, log)
122	}
