265	func (s *AuditService) computeBatchHash(entries []models.AuditLog) string {
266		hasher := sha256.New()
267		for _, e := range entries {
268			// Hash each entry's content hash (or reconstruct from fields)
269			content := fmt.Sprintf("%s|%s|%s|%s|%s|%s",
270				e.ID, e.EntityType, e.EntityID, e.Action, e.ActorID, e.CreatedAt.Format(time.RFC3339Nano))
271			if e.ContentHash != nil {
272				content += "|" + *e.ContentHash
273			}
274			hasher.Write([]byte(content))
275		}
276		return hex.EncodeToString(hasher.Sum(nil))
277	}
