// DeleteExpiredIdempotencyKeyForAccountAndKey removes an expired key for a specific
// account/key combo, allowing the same idempotency key to be reused after the 24h window.
func (r *PaymentRepository) DeleteExpiredIdempotencyKeyForAccountAndKey(ctx context.Context, accountID uuid.UUID, key string, now time.Time) error {
	_, err := r.db.ExecContext(ctx,
		`DELETE FROM idempotency_keys WHERE account_id = $1 AND idempotency_key = $2 AND window_end <= $3`,
