103			WindowStart:    now,
104			WindowEnd:      now.Add(24 * time.Hour),
105			CreatedAt:      now,
106		}
107	
108		// Simulate check at now + 1h: window_end > checkTime
109		checkTime := now.Add(1 * time.Hour)
110		if !checkTime.Before(ik.WindowEnd) {
111			t.Error("key should be active at now+1h (within 24h window)")
112		}
113	}
