115	func TestIdempotencyNewCreateAfter24h(t *testing.T) {
116		// After 24h window, the same key should allow new creation
117		now := time.Now()
118		ik := models.IdempotencyKey{
119			ID:             uuid.New(),
120			AccountID:      uuid.New(),
121			IdempotencyKey: "pay-dup-001",
122			PaymentID:      uuid.New(),
123			WindowStart:    now.Add(-25 * time.Hour),
124			WindowEnd:      now.Add(-1 * time.Hour),
125			CreatedAt:      now.Add(-25 * time.Hour),
126		}
127	
128		// At current time, window_end is in the past
129		if now.Before(ik.WindowEnd) {
130			t.Error("key should be expired after 24h window")
131		}
132	
133		// A new key with the same account+idempotency_key but different window_start
134		// should be allowed by the unique index (account_id, idempotency_key, window_start)
135		newIK := models.IdempotencyKey{
136			ID:             uuid.New(),
137			AccountID:      ik.AccountID,
138			IdempotencyKey: ik.IdempotencyKey,
139			PaymentID:      uuid.New(),
140			WindowStart:    now,
141			WindowEnd:      now.Add(24 * time.Hour),
142			CreatedAt:      now,
143		}
144	
145		// window_start values differ, so unique(account_id, key, window_start) allows this
